import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as t,c as o,e as i}from"./chunks/vendor-mermaid.BXjKBAcr.js";const m=JSON.parse('{"title":"NGO & INGO Sector","description":"Donor compliance, tax exemption renewal, and project audits for the social sector.","frontmatter":{"title":"NGO & INGO Sector","description":"Donor compliance, tax exemption renewal, and project audits for the social sector.","icon":"🤝","parent":"Industries|/industries/","layout":"doc","stats":[{"label":"Donor Audits","value":"USAID/EU/UN"},{"label":"Compliance","value":"SWC Liaison"},{"label":"Tax","value":"Exemption Cert"},{"label":"Framework","value":"Restricted Fund"}],"head":[["meta",{"property":"og:image","content":"https://arthaadvisory.com.np/og_image_test.jpg"}],["meta",{"property":"og:title","content":"NGO & INGO Sector | Artha Advisory"}],["meta",{"property":"og:description","content":"Donor compliance, tax exemption renewal, and project audits for the social sector."}],["meta",{"name":"description","content":"Donor compliance, tax exemption renewal, and project audits for the social sector."}]]},"headers":[],"relativePath":"industries/ngo-ingo.md","filePath":"industries/ngo-ingo.md"}'),n={name:"industries/ngo-ingo.md"};function r(l,a,s,c,d,u){return t(),o("div",null,[...a[0]||(a[0]=[i('<p>Artha Advisory empowers non-profit organizations to focus on their mission while we handle the complex web of donor requirements and government regulations. We serve local NGOs, International NGOs (INGOs), and Foundations.</p><hr><h2 id="🏛️-regulatory-compliance-swc-dao" tabindex="-1">🏛️ Regulatory Compliance (SWC &amp; DAO) <a class="header-anchor" href="#🏛️-regulatory-compliance-swc-dao" aria-label="Permalink to &quot;🏛️ Regulatory Compliance (SWC &amp; DAO)&quot;">​</a></h2><h3 id="_1-social-welfare-council-swc" tabindex="-1">1. Social Welfare Council (SWC) <a class="header-anchor" href="#_1-social-welfare-council-swc" aria-label="Permalink to &quot;1. Social Welfare Council (SWC)&quot;">​</a></h3><ul><li><strong>Affiliation &amp; Renewal</strong>: Guiding new NGOs through SWC affiliation and periodic renewals.</li><li><strong>Project Approval</strong>: Assisting in the financial budgeting for General Agreements (GA) and Project Agreements (PA).</li><li><strong>Project Audit</strong>: Conducting the mandatory project completion audit required by SWC.</li></ul><h3 id="_2-statutory-obligations" tabindex="-1">2. Statutory Obligations <a class="header-anchor" href="#_2-statutory-obligations" aria-label="Permalink to &quot;2. Statutory Obligations&quot;">​</a></h3><ul><li><strong>DAO Renewal</strong>: Ensuring all minute books and audit reports are ready for District Administration Office renewal.</li><li><strong>Tax Exemption</strong>: Applying for and renewing the &quot;Tax Exempt Entity&quot; certificate under the Income Tax Act.</li></ul><hr><h2 id="🌍-donor-compliance-reporting" tabindex="-1">🌍 Donor Compliance &amp; Reporting <a class="header-anchor" href="#🌍-donor-compliance-reporting" aria-label="Permalink to &quot;🌍 Donor Compliance &amp; Reporting&quot;">​</a></h2><h3 id="_1-grant-management" tabindex="-1">1. Grant Management <a class="header-anchor" href="#_1-grant-management" aria-label="Permalink to &quot;1. Grant Management&quot;">​</a></h3><ul><li><strong>Fund Accounting</strong>: Setting up systems to track Restricted vs. Unrestricted funds separately.</li><li><strong>Donor-Specific Reporting</strong>: Preparing financial reports in specific formats (USAID SF-425, EU Financial Statement, UN FACE Forms).</li><li><strong>Overhead Negotiation</strong>: Justifying administrative overhead allocation (NICRA) to donors.</li></ul><h3 id="_2-social-audit-impact" tabindex="-1">2. Social Audit &amp; Impact <a class="header-anchor" href="#_2-social-audit-impact" aria-label="Permalink to &quot;2. Social Audit &amp; Impact&quot;">​</a></h3><ul><li><strong>Social Audit</strong>: Facilitating the mandatory public hearing and social audit process at the local ward level.</li><li><strong>Value for Money (VfM)</strong>: Analyzing the economy, efficiency, and effectiveness of program spends.</li></ul><hr><h2 id="🤝-strategic-advisory" tabindex="-1">🤝 Strategic Advisory <a class="header-anchor" href="#🤝-strategic-advisory" aria-label="Permalink to &quot;🤝 Strategic Advisory&quot;">​</a></h2><h3 id="_1-proposal-writing" tabindex="-1">1. Proposal Writing <a class="header-anchor" href="#_1-proposal-writing" aria-label="Permalink to &quot;1. Proposal Writing&quot;">​</a></h3><ul><li><strong>Budgeting</strong>: Creating detailed financial proposals for grant applications.</li><li><strong>Sub-Grantee Management</strong>: Assessing the financial capacity of local partners before disbursement.</li></ul><h3 id="_2-hr-admin" tabindex="-1">2. HR &amp; Admin <a class="header-anchor" href="#_2-hr-admin" aria-label="Permalink to &quot;2. HR &amp; Admin&quot;">​</a></h3><ul><li><strong>Expat Visa</strong>: Managing work visas for international country directors and volunteers.</li><li><strong>Remote Field Audit</strong>: Sending teams to remote project districts to verify field expenditures.</li></ul><hr><h3 id="is-your-project-audit-delaying-funding" tabindex="-1">Is Your Project Audit Delaying Funding? <a class="header-anchor" href="#is-your-project-audit-delaying-funding" aria-label="Permalink to &quot;Is Your Project Audit Delaying Funding?&quot;">​</a></h3><p>We specialize in rapid-turnaround project audits to ensure your next tranche of funding isn&#39;t stuck.</p><p><a href="/contact"><strong>Contact Our Development Desk</strong></a></p>',23)])])}const h=e(n,[["render",r]]);export{m as __pageData,h as default};
